#include <HX711.h>
#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#include <math.h>
#define NUM_CELLS 4
#define ONE_WIRE_BUS 2
#define BUZZER_PIN 8
#define LED_PIN 9
#define SD_CS 10
#define WALL_H 3.0f
#define PHI_DEG 30.0f
#define GAMMA 18.0f
#define COHESION 5.0f
#define ALARM_R 0.90f
HX711 cells[NUM_CELLS];
const int DOUT[]={A0,A1,A2,A3},CLK[]={A4,A5,4,5};
OneWire ow(ONE_WIRE_BUS); DallasTemperature ds(&ow);
float intg=0,lastE=0;

float rankine_active_pressure(float phi_deg,float gamma_kNm3,float depth_m,float cohesion_kPa){
  float phi=phi_deg*PI/180.0f;
  float Ka=(1.0f-sin(phi))/(1.0f+sin(phi));
  float s=Ka*gamma_kNm3*depth_m-2.0f*cohesion_kPa*sqrt(Ka);
  return s<0?0:s;
}

void setup_sensors(){
  for(int i=0;i<NUM_CELLS;i++){cells[i].begin(DOUT[i],CLK[i]);cells[i].set_scale(420.0f);cells[i].tare();}
  ds.begin();
}

float read_total_force(){
  ds.requestTemperatures();
  float drift=(ds.getTempCByIndex(0)-25.0f)*0.05f;
  float tot=0;
  for(int i=0;i<NUM_CELLS;i++) tot+=cells[i].get_units(3)-drift;
  return tot;
}

float compute_limit(){
  float sigma=rankine_active_pressure(PHI_DEG,GAMMA,WALL_H,COHESION);
  return sigma*WALL_H*1000.0f;
}

void run_pid_guard(float force,float limit){
  float sp=0.80f*limit,e=force-sp;
  intg+=e*0.1f; intg=constrain(intg,-1000,1000);
  float d=(e-lastE)/0.1f; lastE=e;
  float out=0.5f*e+0.1f*intg+0.05f*d;
  if(out>0&&force>ALARM_R*limit){digitalWrite(BUZZER_PIN,HIGH);analogWrite(LED_PIN,255);}
  else{digitalWrite(BUZZER_PIN,LOW);analogWrite(LED_PIN,(int)(force/limit*200));}
}

void log_data(float force,float limit){
  File f=SD.open("retwall.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.print(force);f.print(',');f.println(limit);f.close();}
}

void setup(){Serial.begin(115200);pinMode(BUZZER_PIN,OUTPUT);pinMode(LED_PIN,OUTPUT);SD.begin(SD_CS);setup_sensors();}

void loop(){
  float force=read_total_force();
  float limit=compute_limit();
  run_pid_guard(force,limit);
  log_data(force,limit);
  Serial.print("F=");Serial.print(force);Serial.print(" Lim=");Serial.println(limit);
  delay(100);
}
